import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import logo from '../assets/Logo.png';

const Header = () => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        axios.get('http://localhost:5000/api/categories')
            .then(res => setCategories(res.data))
            .catch(err => console.error(err));
    }, []);

    return (
        <header className="bg-white border-bottom sticky-top">
            <div className="container py-3">
                <div className="row align-items-center">

                    <div className="col-8 col-md-4">
                        <Link to="/">
                            <img src={logo} alt="Logo" style={{ width: '250px', height: 'auto' }} />
                        </Link>
                    </div>

                    <div className="col-4 d-md-none text-end">
                        <button className="navbar-toggler border-0" type="button" data-bs-toggle="collapse" data-bs-target="#navigationUnique">
                            <span className="navbar-toggler-icon"></span>
                        </button>
                    </div>

                    <div className="col-12 col-md-8 collapse d-md-block" id="navigationUnique">
                        <div className="d-flex flex-column align-items-center align-items-md-end mt-3 mt-md-0">
                            
                            <div className="position-relative mb-2" style={{ width: '250px' }}>
                                <input 
                                    className="form-control border-0 border-bottom rounded-0 shadow-none ps-0" 
                                    type="text" 
                                    placeholder="Rechercher"
                                    style={{ borderBottom: '2px solid #004a99' }}
                                />
                                <span className="position-absolute end-0 top-50 translate-middle-y">🔍</span>
                            </div>

                            <nav>
                                <ul className="nav justify-content-center justify-content-md-end">
                                    {categories.map((cat) => (
                                        <li className="nav-item" key={cat.id}>
                                            <Link className="nav-link text-dark fw-bold px-2" to={`/category/${cat.id}`}>
                                                {cat.name}
                                            </Link>
                                        </li>
                                    ))}
                                </ul>
                            </nav>
                        </div>
                    </div>
                </div>
            </div>
        </header>
    );
};

export default Header;
